class Solution:
    def maximumUniqueSubarray(self, nums):
        n = len(nums)
        best = 0
        for i in range(n):
            seen = set()
            total = 0
            for j in range(i, n):
                if nums[j] in seen:
                    break
                seen.add(nums[j])
                total += nums[j]
                if total > best:
                    best = total
        return best

