class Solution:
    def maximumUniqueSubarray(self, nums: List[int]) -> int:
        seen = set()
        left = 0
        window_sum = 0
        best = 0
        for right, v in enumerate(nums):
            while v in seen:
                seen.remove(nums[left])
                window_sum -= nums[left]
                left += 1
            seen.add(v)
            window_sum += v
            if window_sum > best:
                best = window_sum
        return best

