var maximumUniqueSubarray = function(nums) {
    const seen = new Set();
    let left = 0;
    let windowSum = 0;
    let best = 0;
    for (let right = 0; right < nums.length; right++) {
        const v = nums[right];
        while (seen.has(v)) {
            seen.delete(nums[left]);
            windowSum -= nums[left];
            left++;
        }
        seen.add(v);
        windowSum += v;
        if (windowSum > best) best = windowSum;
    }
    return best;
};
